using System.IO;
using System.Collections.Generic;
using System.Threading.Tasks;

namespace YourNamespace.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class UploadController : ControllerBase
    {
        private readonly IWebHostEnvironment _webHostEnvironment;
        private const string UploadsFolderName = "uploads";

        public UploadController(IWebHostEnvironment webHostEnvironment)
        {
            _webHostEnvironment = webHostEnvironment;
        }

        [HttpPost]
        public async Task<IActionResult> UploadFiles(List<IFormFile> files)
        {
            if (files == null || files.Count == 0)
            {
                return BadRequest("No files selected for upload.");
            }

            var uploadedFilePaths = new List<string>();
            var uploadsPath = Path.Combine(_webHostEnvironment.WebRootPath, UploadsFolderName);

            if (!Directory.Exists(uploadsPath))
            {
                Directory.CreateDirectory(uploadsPath);
            }

            foreach (var file in files)
            {
                if (file.Length == 0)
                {
                    continue; // Skip empty files
                }

                try
                {
                    var fileExtension = Path.GetExtension(file.FileName);
                    var uniqueFileName = $"{Guid.NewGuid()}{fileExtension}";
                    var fullFilePath = Path.Combine(uploadsPath, uniqueFileName);

                    using (var stream = new FileStream(fullFilePath, FileMode.Create))
                    {
                        await file.CopyToAsync(stream);
                    }

                    // Store the relative path to be returned
                    uploadedFilePaths.Add($"/{UploadsFolderName}/{uniqueFileName}");
                }
                catch (Exception ex)
                {
                    // Log the exception (e.g., using ILogger)
                    return StatusCode(500, $"Internal server error: {ex.Message}");
                }
            }

            return Ok(new { FilePaths = uploadedFilePaths });
